# Terraform — no circular dependency with user-assigned

# Step 1: Create the identity (no dependency on the VM)
resource "azurerm_user_assigned_identity" "app" {
  name                = "my-app-identity"
  resource_group_name = azurerm_resource_group.rg.name
  location            = azurerm_resource_group.rg.location
}

# Step 2: Assign role using identity's principal_id (VM not yet created)
resource "azurerm_role_assignment" "kv" {
  scope                = azurerm_key_vault.kv.id
  role_definition_name = "Key Vault Secrets User"
  principal_id         = azurerm_user_assigned_identity.app.principal_id
}

# Step 3: Create VM and attach — role already exists
resource "azurerm_linux_virtual_machine" "vm" {
  name                = "MyVM"
  resource_group_name = azurerm_resource_group.rg.name
  location            = azurerm_resource_group.rg.location
  size                = "Standard_B2s"

  identity {
    type         = "UserAssigned"
    identity_ids = [azurerm_user_assigned_identity.app.id]
  }
  depends_on = [azurerm_role_assignment.kv]
  # ... other required properties
}

using Azure.Identity;
using Azure.Security.KeyVault.Secrets;

// System-assigned (or single user-assigned): no configuration needed
var credential1 = new DefaultAzureCredential();

// User-assigned with explicit client ID (when multiple are attached)
var userAssignedClientId = Environment.GetEnvironmentVariable("AZURE_CLIENT_ID");
var credential2 = new DefaultAzureCredential(
    new DefaultAzureCredentialOptions {
        ManagedIdentityClientId = userAssignedClientId
    }
);

var client = new SecretClient(
    new Uri("https://mykeyvault.vault.azure.net"),
    credential2
);
var secret = await client.GetSecretAsync("my-secret");

# Query identity type and principal IDs on a VM
az vm show \
    --resource-group RG \
    --name MyVM \
    --query '{
        identityType: identity.type,
        systemPrincipalId: identity.principalId,
        userIdentities: identity.userAssignedIdentities
    }' \
    --output json

# Sample output for mixed identity type:
# {
#   "identityType": "SystemAssigned, UserAssigned",
#   "systemPrincipalId": "aaaabbbb-...",
#   "userIdentities": {
#     "/subscriptions/.../my-shared-identity": {
#       "clientId": "ccccdddd-...",
#       "principalId": "eeeeffff-..."
#     }
#   }
# }

// Azure Policy definition — deny VMs with system-assigned identity only
// Enforces user-assigned identity for auditing stability
{
  "if": {
    "allOf": [
      { "field": "type", "equals": "Microsoft.Compute/virtualMachines" },
      {
        "field": "identity.type",
        "in": ["SystemAssigned", "SystemAssigned, UserAssigned"]
      }
    ]
  },
  "then": {
    "effect": "deny"
  }
}
// Apply in 'audit' mode first to assess scope before switching to 'deny'
